+    fn deserialize<D: serde::Deserializer<'de>>(deserializer: D) -> Result<Self, D::Error> {
+        let value = String::deserialize(deserializer)?;
+        Ok(match value.to_lowercase().as_str() {
+            "task" => Self::Task,
+            "bug" => Self::Bug,
+            "feature" => Self::Feature,
+            "epic" => Self::Epic,
+            "chore" => Self::Chore,
+            "docs" => Self::Docs,
+            "question" => Self::Question,
+            _ => Self::Custom(value),
+        })
+    }
